autoware::pointcloud_preprocessor::Filter::Filter(
  const std::string & filter_name, const rclcpp::NodeOptions & options)
: Node(filter_name, options), filter_field_name_(filter_name)
{
  // Set parameters (moved from NodeletLazy onInit)
  {
    tf_input_frame_ = static_cast<std::string>(declare_parameter("input_frame", ""));
    tf_output_frame_ = static_cast<std::string>(declare_parameter("output_frame", ""));
    max_queue_size_ = static_cast<std::size_t>(declare_parameter("max_queue_size", 5));

    // ---[ Optional parameters
    use_indices_ = static_cast<bool>(declare_parameter("use_indices", false));
    latched_indices_ = static_cast<bool>(declare_parameter("latched_indices", false));
    approximate_sync_ = static_cast<bool>(declare_parameter("approximate_sync", false));

    RCLCPP_DEBUG_STREAM(
      this->get_logger(),
      "Filter (as Component) successfully created with the following parameters:"
        << std::endl
        << " - approximate_sync : " << (approximate_sync_ ? "true" : "false") << std::endl
        << " - use_indices      : " << (use_indices_ ? "true" : "false") << std::endl
        << " - latched_indices  : " << (latched_indices_ ? "true" : "false") << std::endl
        << " - max_queue_size   : " << max_queue_size_);
  }

  // Set publisher
  {
    rclcpp::PublisherOptions pub_options;
    pub_options.qos_overriding_options = rclcpp::QosOverridingOptions::with_default_policies();
    pub_output_ = this->create_publisher<PointCloud2>(
      "output", rclcpp::SensorDataQoS().keep_last(max_queue_size_), pub_options);
  }

  subscribe(filter_name);

  // Set tf_listener, tf_buffer.
  setup_tf();

  // Set parameter service callback
  set_param_res_filter_ = this->add_on_set_parameters_callback(
    std::bind(&Filter::filter_param_callback, this, std::placeholders::_1));

  published_time_publisher_ = std::make_unique<autoware_utils::PublishedTimePublisher>(this);
  RCLCPP_DEBUG(this->get_logger(), "[Filter Constructor] successfully created.");
}

void autoware::pointcloud_preprocessor::Filter::subscribe(const std::string & filter_name)
{
  // TODO(sykwer): Change the corresponding node to subscribe to `faster_input_indices_callback`
  // each time a child class supports the faster version.
  // When all the child classes support the faster version, this workaround is deleted.
  std::set<std::string> supported_nodes = {
    "CropBoxFilter", "RingOutlierFilter", "VoxelGridDownsampleFilter", "ScanGroundFilter",
    "PointCloudDensifier"};
  auto callback = supported_nodes.find(filter_name) != supported_nodes.end()
                    ? &Filter::faster_input_indices_callback
                    : &Filter::input_indices_callback;

  if (use_indices_) {
    // Subscribe to the input using a filter
    sub_input_filter_.subscribe(
      this, "input", rclcpp::SensorDataQoS().keep_last(max_queue_size_).get_rmw_qos_profile());
    sub_indices_filter_.subscribe(
      this, "indices", rclcpp::SensorDataQoS().keep_last(max_queue_size_).get_rmw_qos_profile());

    if (approximate_sync_) {
      sync_input_indices_a_ = std::make_shared<ApproximateTimeSyncPolicy>(max_queue_size_);
      sync_input_indices_a_->connectInput(sub_input_filter_, sub_indices_filter_);
      sync_input_indices_a_->registerCallback(
        std::bind(callback, this, std::placeholders::_1, std::placeholders::_2));
    } else {
      sync_input_indices_e_ = std::make_shared<ExactTimeSyncPolicy>(max_queue_size_);
      sync_input_indices_e_->connectInput(sub_input_filter_, sub_indices_filter_);
      sync_input_indices_e_->registerCallback(
        std::bind(callback, this, std::placeholders::_1, std::placeholders::_2));
    }
  } else {
    // Subscribe in an old fashion to input only (no filters)
    // CAN'T use auto-type here.
    std::function<void(const PointCloud2ConstPtr msg)> cb =
      std::bind(callback, this, std::placeholders::_1, PointIndicesConstPtr());
    sub_input_ = create_subscription<PointCloud2>(
      "input", rclcpp::SensorDataQoS().keep_last(max_queue_size_), cb);
  }
}

void autoware::pointcloud_preprocessor::Filter::input_indices_callback(
  const PointCloud2ConstPtr cloud, const PointIndicesConstPtr indices)
{
  if (!is_valid(cloud, this->get_logger(), *this->get_clock())) {
    RCLCPP_ERROR(this->get_logger(), "[input_indices_callback] Invalid input!");
    return;
  }

  /// DEBUG
  if (indices) {
    if (!is_valid_indices(indices, cloud->width * cloud->height, this->get_logger())) {
      RCLCPP_ERROR(this->get_logger(), "[input_indices_callback] Invalid indices!");
      return;
    }

    RCLCPP_DEBUG(
      this->get_logger(),
      "[input_indices_callback]\n"
      "   - PointCloud with %d data points (%s), stamp %f, and frame %s on input topic received.\n"
      "   - PointIndices with %zu values, stamp %f, and frame %s on indices topic received.",
      cloud->width * cloud->height, pcl::getFieldsList(*cloud).c_str(),
      rclcpp::Time(cloud->header.stamp).seconds(), cloud->header.frame_id.c_str(),
      indices->indices.size(), rclcpp::Time(indices->header.stamp).seconds(),
      indices->header.frame_id.c_str());
  } else {
    RCLCPP_DEBUG(
      this->get_logger(),
      "[input_indices_callback] PointCloud with %d data points and frame %s on input topic "
      "received.",
      cloud->width * cloud->height, cloud->header.frame_id.c_str());
  }
  ///

  // Check whether the user has given a different input TF frame
  tf_input_orig_frame_ = cloud->header.frame_id;
  PointCloud2ConstPtr cloud_tf;
  if (!tf_input_frame_.empty() && cloud->header.frame_id != tf_input_frame_) {
    RCLCPP_DEBUG(
      this->get_logger(), "[input_indices_callback] Transforming input dataset from %s to %s.",
      cloud->header.frame_id.c_str(), tf_input_frame_.c_str());
    // Save the original frame ID
    // Convert the cloud into the different frame
    PointCloud2 cloud_transformed;

    if (!managed_tf_buffer_->transformPointcloud(
          tf_input_frame_, *cloud, cloud_transformed, cloud->header.stamp,
          rclcpp::Duration::from_seconds(1.0), this->get_logger())) {
      return;
    }
    cloud_tf = std::make_shared<PointCloud2>(cloud_transformed);
  } else {
    cloud_tf = cloud;
  }
  // Need setInputCloud () here because we have to extract x/y/z
  IndicesPtr vindices;
  if (indices) {
    vindices.reset(new std::vector<int>(indices->indices));
  }

  compute_publish(cloud_tf, vindices);
}

void autoware::pointcloud_preprocessor::Filter::compute_publish(
  const PointCloud2ConstPtr & input, const IndicesPtr & indices)
{
  auto output = std::make_unique<PointCloud2>();

  // Call the virtual method in the child
  filter(input, indices, *output);

  if (!convert_output_costly(output)) return;

  // Copy timestamp to keep it
  output->header.stamp = input->header.stamp;

  // Publish a boost shared ptr
  pub_output_->publish(std::move(output));
  published_time_publisher_->publish_if_subscribed(pub_output_, input->header.stamp);
}

bool autoware::pointcloud_preprocessor::Filter::convert_output_costly(
  std::unique_ptr<PointCloud2> & output)
{
  // In terms of performance, we should avoid using pcl_ros library function,
  // but this code path isn't reached in the main use case of Autoware, so it's left as is for now.
  if (!tf_output_frame_.empty() && output->header.frame_id != tf_output_frame_) {
    RCLCPP_DEBUG(
      this->get_logger(), "[convert_output_costly] Transforming output dataset from %s to %s.",
      output->header.frame_id.c_str(), tf_output_frame_.c_str());

    // Convert the cloud into the different frame
    auto cloud_transformed = std::make_unique<PointCloud2>();

    if (!managed_tf_buffer_->transformPointcloud(
          tf_output_frame_, *output, *cloud_transformed, output->header.stamp,
          rclcpp::Duration::from_seconds(1.0), this->get_logger())) {
      RCLCPP_ERROR(
        this->get_logger(),
        "[convert_output_costly] Error converting output dataset from %s to %s.",
        output->header.frame_id.c_str(), tf_output_frame_.c_str());
      return false;
    }

    output = std::move(cloud_transformed);
  }

  // Same as the comment above
  if (tf_output_frame_.empty() && output->header.frame_id != tf_input_orig_frame_) {
    // No tf_output_frame given, transform the dataset to its original frame
    RCLCPP_DEBUG(
      this->get_logger(), "[convert_output_costly] Transforming output dataset from %s back to %s.",
      output->header.frame_id.c_str(), tf_input_orig_frame_.c_str());

    auto cloud_transformed = std::make_unique<PointCloud2>();

    if (!managed_tf_buffer_->transformPointcloud(
          tf_input_orig_frame_, *output, *cloud_transformed, output->header.stamp,
          rclcpp::Duration::from_seconds(1.0), this->get_logger())) {
      return false;
    }

    output = std::move(cloud_transformed);
  }

  return true;
}

bool ManagedTransformBuffer::transformPointcloud(
  const std::string & target_frame, const sensor_msgs::msg::PointCloud2 & cloud_in,
  sensor_msgs::msg::PointCloud2 & cloud_out, const rclcpp::Time & time,
  const rclcpp::Duration & timeout, const rclcpp::Logger & logger)
{
  return transformPointcloud(
    target_frame, cloud_in, cloud_out, tf2_ros::fromRclcpp(time), tf2_ros::fromRclcpp(timeout),
    logger);
}

static bool is_valid(
  const PointCloud2ConstPtr & cloud, const rclcpp::Logger & logger, rclcpp::Clock & clock)
{
  static constexpr rcutils_duration_value_t throttle_duration_ms = 5000;

  if (!cloud) {
    RCLCPP_WARN_THROTTLE(
      logger, clock, throttle_duration_ms, "Invalid PointCloud: Null pointer received.");
    return false;
  }

  // Check: Point Step
  if (cloud->point_step == 0) {
    RCLCPP_WARN_THROTTLE(
      logger, clock, throttle_duration_ms,
      "Invalid PointCloud: point_step is 0. "
      "Frame: '%s', Stamp: %d.%09u",
      cloud->header.frame_id.c_str(), cloud->header.stamp.sec, cloud->header.stamp.nanosec);
    return false;
  }

  // Check: Only accept organized (dense) point clouds
  if (!cloud->is_dense) {
    RCLCPP_WARN_THROTTLE(
      logger, clock, throttle_duration_ms,
      "Invalid PointCloud: is_dense is false. "
      "The point cloud should be organized (dense) and contain only valid points. "
      "This will be an ERROR starting in 2026 July"
      "Frame: '%s', Stamp: %d.%09u",
      cloud->header.frame_id.c_str(), cloud->header.stamp.sec, cloud->header.stamp.nanosec);
    // TODO(mfc): return false; After 2026 July
  }

  // Check: Point field layout compatibility
  if (!utils::is_data_layout_compatible_with_point_xyz(*cloud)) {
    RCLCPP_WARN_THROTTLE(
      logger, clock, throttle_duration_ms,
      "The pointcloud layout is not compatible with PointXYZ. Aborting. "
      "Make sure Point fields start with x, y, z as FLOAT32.");
    return false;
  }

  // Check: Row step consistency
  std::uint64_t expected_row_step =
    static_cast<std::uint64_t>(cloud->width) * static_cast<std::uint64_t>(cloud->point_step);

  if (expected_row_step != static_cast<std::uint64_t>(cloud->row_step)) {
    RCLCPP_WARN_THROTTLE(
      logger, clock, throttle_duration_ms,
      "Invalid PointCloud: row_step mismatch. "
      "Expected: %zu (width %u * point_step %u), Got: %u. "
      "Frame: '%s', Stamp: %d.%09u"
      " Please fill in the `cloud->row_step` field accordingly."
      " This will be an ERROR starting in 2026 July",
      expected_row_step, cloud->width, cloud->point_step, cloud->row_step,
      cloud->header.frame_id.c_str(), cloud->header.stamp.sec, cloud->header.stamp.nanosec);
    // TODO(mfc): return false; After 2026 July
  }

  // Check: Data buffer size consistency
  std::uint64_t expected_data_size =
    static_cast<std::uint64_t>(cloud->height) * expected_row_step;

  if (expected_data_size != cloud->data.size()) {
    RCLCPP_WARN_THROTTLE(
      logger, clock, throttle_duration_ms,
      "Invalid PointCloud: data size mismatch. "
      "Expected: %zu (height %u * row_step %u), Got: %zu. "
      "Frame: '%s', Stamp: %d.%09u",
      expected_data_size, cloud->height, cloud->row_step, cloud->data.size(),
      cloud->header.frame_id.c_str(), cloud->header.stamp.sec, cloud->header.stamp.nanosec);
    return false;
  }

  return true;
}

bool is_data_layout_compatible_with_point_xyz(
  const std::vector<sensor_msgs::msg::PointField> & fields)
{
  if (fields.size() < 3) {
    return false;
  }

  // Expected PointXYZ layout:
  // struct { float x; float y; float z; }
  constexpr size_t offset_x = 0;
  constexpr size_t offset_y = sizeof(float);
  constexpr size_t offset_z = sizeof(float) * 2;

  bool same_layout = true;

  const auto & field_x = fields[0];
  same_layout &= field_x.name == "x";
  same_layout &= field_x.offset == offset_x;
  same_layout &= field_x.datatype == sensor_msgs::msg::PointField::FLOAT32;
  same_layout &= field_x.count == 1;

  const auto & field_y = fields[1];
  same_layout &= field_y.name == "y";
  same_layout &= field_y.offset == offset_y;
  same_layout &= field_y.datatype == sensor_msgs::msg::PointField::FLOAT32;
  same_layout &= field_y.count == 1;

  const auto & field_z = fields[2];
  same_layout &= field_z.name == "z";
  same_layout &= field_z.offset == offset_z;
  same_layout &= field_z.datatype == sensor_msgs::msg::PointField::FLOAT32;
  same_layout &= field_z.count == 1;

  return same_layout;
}

static bool is_valid_indices(
  const PointIndicesConstPtr & indices, size_t cloud_size, const rclcpp::Logger & logger)
{
  if (!indices) {
    RCLCPP_WARN(logger, "PointIndices pointer is null");
    return false;
  }

  // Valid special case: empty indices
  if (indices->indices.empty()) {
    return true;
  }

  // Assumption: Indices represent a subset/filter.
  if (indices->indices.size() > cloud_size) {
    RCLCPP_WARN(
      logger, "Received %zu indices for a cloud with %zu points", indices->indices.size(),
      cloud_size);
    return false;
  }

  for (const std::int32_t idx : indices->indices) {
    // Optimization: Hint to branch predictor that invalid indices are rare.
    // TODO(mfc): Replace __builtin_expect with [[unlikely]] when upgrading to C++20.
    if (__builtin_expect(idx < 0 || static_cast<size_t>(idx) >= cloud_size, 0)) {
      RCLCPP_WARN(logger, "Invalid point index detected: %d (cloud size: %zu)", idx, cloud_size);
      return false;
    }
  }

  return true;
}

Connection registerCallback(const C& callback)
{
  return signal_.addCallback(callback);
}
